def fact(n):
    if n==1:
        return 1
    return n*fact(n-1)

def two_sum(arr,t):
 for i in arr:
  for j in arr:
   if i+j==t: return i,j

def fib(n):
    if n <= 1:
        return n
    return fib(n-1)+fib(n-2)

def find_max(arr):
    max_val = 0
    for x in arr:
        if x > max_val:
            max_val = x
    return max_val
